"use client"

import * as React from "react"

import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"

export interface DialogState {
  isOpen: boolean
  title?: string
  description?: string
  content?: React.ReactNode
}

export interface DialogOptions extends Omit<DialogState, "isOpen"> {
  onConfirm?: () => void
}

export interface DialogDispatch {
  openDialog: (options: DialogOptions) => void
  closeDialog: () => void
}

const DialogContext = React.createContext<DialogDispatch | undefined>(undefined)

export interface DialogProviderProps {
  children: React.ReactNode
}

export function DialogProvider({ children }: DialogProviderProps) {
  const [dialog, setDialog] = React.useState<DialogState>({ isOpen: false })

  const openDialog = React.useCallback((options: DialogOptions) => {
    setDialog({ ...options, isOpen: true })
  }, [])

  const closeDialog = React.useCallback(() => {
    setDialog((prev) => ({ ...prev, isOpen: false }))
  }, [])

  return (
    <DialogContext.Provider value={{ openDialog, closeDialog }}>
      {children}
      <Dialog
        open={dialog.isOpen}
        onOpenChange={(open) => {
          if (!open) closeDialog()
        }}
      >
        <DialogContent>
          {dialog.title ? (
            <DialogHeader>
              <DialogTitle>{dialog.title}</DialogTitle>
              {dialog.description ? (
                <DialogDescription>{dialog.description}</DialogDescription>
              ) : null}
            </DialogHeader>
          ) : null}
          {dialog.content}
        </DialogContent>
      </Dialog>
    </DialogContext.Provider>
  )
}

export function useDialog() {
  return React.useContext(DialogContext)
}

"use client"

import * as React from "react"

import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"

type AlertResolver = () => void
type ConfirmResolver = (value: boolean) => void

interface AlertDialogState {
  isOpen: boolean
  kind: "alert" | "confirm"
  title: string
  message: string
}

export interface AlertDialogDispatch {
  alert: (title: string, message: string) => Promise<void>
  confirm: (title: string, message: string) => Promise<boolean>
}

const AlertDialogContext = React.createContext<
  AlertDialogDispatch | undefined
>(undefined)

export interface AlertDialogProviderProps {
  children: React.ReactNode
}

export function AlertDialogProvider({ children }: AlertDialogProviderProps) {
  const [state, setState] = React.useState<AlertDialogState>({
    isOpen: false,
    kind: "alert",
    title: "",
    message: "",
  })
  const resolverRef = React.useRef<AlertResolver | ConfirmResolver | null>(null)

  const close = React.useCallback((value: boolean) => {
    const resolve = resolverRef.current
    resolverRef.current = null
    setState((prev) => ({ ...prev, isOpen: false }))
    if (resolve) {
      ;(resolve as ConfirmResolver)(value)
    }
  }, [])

  const alert = React.useCallback((title: string, message: string): Promise<void> => {
    return new Promise<void>((resolve) => {
      resolverRef.current = resolve as AlertResolver
      setState({ isOpen: true, kind: "alert", title, message })
    })
  }, [])

  const confirm = React.useCallback(
    (title: string, message: string): Promise<boolean> => {
      return new Promise<boolean>((resolve) => {
        resolverRef.current = resolve as ConfirmResolver
        setState({ isOpen: true, kind: "confirm", title, message })
      })
    },
    [],
  )

  return (
    <AlertDialogContext.Provider value={{ alert, confirm }}>
      {children}
      <AlertDialog
        open={state.isOpen}
        onOpenChange={(open) => {
          if (!open) close(false)
        }}
      >
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{state.title}</AlertDialogTitle>
            <AlertDialogDescription>{state.message}</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            {state.kind === "confirm" ? (
              <AlertDialogCancel onClick={() => close(false)}>Cancel</AlertDialogCancel>
            ) : null}
            <AlertDialogAction onClick={() => close(true)}>
              {state.kind === "confirm" ? "Confirm" : "OK"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </AlertDialogContext.Provider>
  )
}

export function useAlertDialog() {
  return React.useContext(AlertDialogContext)
}

export const useAlert = () => useAlertDialog()?.alert

export const useConfirm = () => useAlertDialog()?.confirm

