export interface CoverViewProps extends React.HTMLAttributes<HTMLDivElement> {
  children?: React.ReactNode
  primaryAction?: React.ReactNode
  secondaryAction?: React.ReactNode
  header?: React.ReactNode
  title?: string
  cover?: string
  scrollable?: boolean
  titleProps?: React.HTMLAttributes<HTMLHeadingElement>
  colorScheme?: ToolbarColorScheme
  loading?: boolean
  coverMinimal?: boolean
  coverFullscreen?: boolean
  stickyContent?: React.ReactNode
  loadingProgress?: number
  contentClassName?: string
}

export const CoverView = React.forwardRef<HTMLDivElement, CoverViewProps>(
  (
    {
      children,
      primaryAction,
      secondaryAction,
      header,
      title,
      cover,
      scrollable = true,
      className,
      titleProps,
      colorScheme = "background",
      loading = false,
      coverMinimal = false,
      coverFullscreen = false,
      stickyContent,
      loadingProgress,
      contentClassName,
      ...props
    },
    ref,
  ) => {
    const isPhone = useIsPhone()
    const scrollAreaRef = React.useRef<HTMLDivElement>(null)
    const scrollViewportRef = React.useRef<HTMLDivElement>(null)

    const scrollEffectsActive = scrollable && !coverMinimal && !coverFullscreen

    const {
      scrollY,
      headerTranslateY,
      headerContentOpacity,
      stickyTranslateY,
      mobileAppBarOpacity,
      mobileAppBarVisibility,
      headerContentVisibility,
      titleFontSize,
      titleFontWeight,
      titlePaddingLeft,
      titlePaddingRight,
      primaryActionTranslateY,
      secondaryActionTranslateY,
    } = useCoverViewScroll({
      showPrimaryAction: Boolean(primaryAction),
      showSecondaryAction: Boolean(secondaryAction),
      scrollViewportRef,
      coverMinimal,
    })

    const colorClasses: Record<ToolbarColorScheme, string> = {
      background: "bg-background text-foreground",
      primary: "bg-primary text-primary-foreground",
      secondary: "bg-secondary text-secondary-foreground",
      accent: "bg-accent text-accent-foreground",
      card: "bg-card text-card-foreground",
      transparent: "",
    }

    return (
      <div
        ref={ref}
        className={cn(
          "relative flex h-full w-full flex-col overflow-hidden bg-background",
          className,
        )}
        {...props}
      >
        {isPhone ? (
          <motion.div
            className="fixed top-0 left-0 z-20 flex h-16 w-full flex-shrink-0 shadow-md"
            style={{
              opacity: coverMinimal ? 1 : mobileAppBarOpacity,
              visibility: mobileAppBarVisibility,
            }}
          >
            <Toolbar
              colorScheme={colorScheme}
              className="flex h-full w-full items-center justify-between px-4"
            >
              <motion.div className="flex-shrink-0">{primaryAction}</motion.div>
              <h2
                className={cn(
                  "mx-4 truncate text-lg font-semibold",
                  colorScheme === "background" && "text-foreground",
                  colorScheme === "primary" && "text-primary-foreground",
                  colorScheme === "secondary" && "text-secondary-foreground",
