import type { RefObject } from "react"
import { useScroll, useTransform, type MotionValue } from "framer-motion"

import { APPBAR_HEIGHT, COVER_HEIGHT } from "./CoverView"

interface UseCoverViewScrollProps {
  scrollViewportRef: RefObject<HTMLDivElement | null>
  coverMinimal: boolean
  showPrimaryAction?: boolean
  showSecondaryAction?: boolean
}

interface CoverViewScrollValues {
  scrollY: MotionValue<number>
  headerTranslateY: MotionValue<number>
  headerContentOpacity: MotionValue<number>
  stickyTranslateY: MotionValue<number>
  mobileAppBarOpacity: MotionValue<number>
  mobileAppBarVisibility: MotionValue<"visible" | "hidden">
  headerContentVisibility: MotionValue<"visible" | "hidden">
  titleFontSize: MotionValue<string>
  titleFontWeight: MotionValue<number>
  titlePaddingLeft: MotionValue<string>
  titlePaddingRight: MotionValue<string>
  primaryActionTranslateY: MotionValue<number>
  secondaryActionTranslateY: MotionValue<number>
}

export function useCoverViewScroll({
  scrollViewportRef,
  coverMinimal,
  showPrimaryAction = false,
  showSecondaryAction = false,
}: UseCoverViewScrollProps): CoverViewScrollValues {
  const SCROLL_RANGE_START = 0
  const SCROLL_RANGE_END = COVER_HEIGHT - APPBAR_HEIGHT
  const COLLAPSED_ACTION_PADDING_Y = COVER_HEIGHT - 65

  const { scrollY } = useScroll({
    container: scrollViewportRef,
  })

  const headerTranslateY = useTransform(
    scrollY,
    [SCROLL_RANGE_START, SCROLL_RANGE_END],
    [0, -(COVER_HEIGHT - APPBAR_HEIGHT)],
    { clamp: true },
  )

  const headerContentOpacity = useTransform(
    scrollY,
    [SCROLL_RANGE_START, SCROLL_RANGE_END * 0.8],
    [1, 0],
    { clamp: true },
  )

  const stickyTranslateY = useTransform(
    scrollY,
    [SCROLL_RANGE_START, SCROLL_RANGE_END],
    [COVER_HEIGHT, APPBAR_HEIGHT],
    { clamp: true },
  )

  const mobileAppBarOpacity = useTransform(
    scrollY,
    [SCROLL_RANGE_END * 0.5, SCROLL_RANGE_END],
    [0, 1],
    { clamp: true },
  )

  const titleFontSize = useTransform(scrollY, [0, SCROLL_RANGE_END], ["2.25rem", "1.125rem"])
  const titleFontWeight = useTransform(scrollY, [0, SCROLL_RANGE_END], [700, 800])

  const titlePaddingLeft = useTransform(
    scrollY,
    [0, SCROLL_RANGE_END],
    ["0rem", showPrimaryAction ? "3rem" : "0rem"],
  )

  const titlePaddingRight = useTransform(
    scrollY,
    [0, SCROLL_RANGE_END],
    ["0rem", showSecondaryAction ? "2rem" : "0rem"],
  )

  const primaryActionTranslateY = useTransform(
    scrollY,
    [0, SCROLL_RANGE_END],
    [0, COLLAPSED_ACTION_PADDING_Y],
  )
  const secondaryActionTranslateY = useTransform(
    scrollY,
    [0, SCROLL_RANGE_END],
    [0, COLLAPSED_ACTION_PADDING_Y],
  )

  const mobileAppBarVisibility = useTransform(mobileAppBarOpacity, (val) =>
    coverMinimal || val > 0 ? "visible" : "hidden",
  )

  const headerContentVisibility = useTransform(headerContentOpacity, (val) =>
    coverMinimal || val > 0 ? "visible" : "hidden",
  )

  return {
    scrollY,
    headerTranslateY,
    headerContentOpacity,
    stickyTranslateY,
    mobileAppBarOpacity,
    mobileAppBarVisibility,
    headerContentVisibility,
    titleFontSize,
    titleFontWeight,
    titlePaddingLeft,
    titlePaddingRight,
    primaryActionTranslateY,
    secondaryActionTranslateY,
  }
}

import type { PanelData, CalculatedPanelState } from "./types"

export interface NaturalLayoutResult {
  numFull: number
  numStacked: number
  numHidden: number
  totalVisibleWidth: number
}

export interface LayoutConfig {
  panelWidth: number
  stackedPanelWidth: number
  maxVisiblePanels: number
  mainViewMinWidth: number
  containerWidth: number
}

export interface PanelLayoutInfo {
  position: {
    right: number
    zIndex: number
    baseWidth: number
  }
  state: CalculatedPanelState["state"]
}

interface LayoutCalculationResult {
  panelLayouts: Map<string, PanelLayoutInfo>
  totalVisibleWidth: number
}

export const calculateNaturalLayout =
  ({
    containerWidth,
    mainViewMinWidth,
    maxVisiblePanels,
    panelWidth,
    stackedPanelWidth,
  }: LayoutConfig) =>
  (panelCount: number): NaturalLayoutResult => {
    const potentialPanelWidth = Math.max(0, containerWidth - mainViewMinWidth)
    const numFull = Math.min(
      panelCount,
      maxVisiblePanels,
      Math.floor(potentialPanelWidth / panelWidth),
    )
    const widthAfterFull = Math.max(0, potentialPanelWidth - numFull * panelWidth)
    const numStacked = Math.min(
      Math.max(0, panelCount - numFull),
      Math.max(0, maxVisiblePanels - numFull),
      Math.floor(widthAfterFull / stackedPanelWidth),
    )
    const numHidden = Math.max(0, panelCount - numFull - numStacked)
    const totalVisibleWidth = numFull * panelWidth + numStacked * stackedPanelWidth
    return { numFull, numStacked, numHidden, totalVisibleWidth }
  }

export function configurePanelLayoutCalculator(config: LayoutConfig): (
  panels: PanelData[],
  naturalLayout: NaturalLayoutResult,
  activePanelIndex: number | null | undefined,
) => LayoutCalculationResult {
  return (
    panels: PanelData[],
    naturalLayout: NaturalLayoutResult,
    activePanelIndex: number | null | undefined,
  ): LayoutCalculationResult => {
    const panelCount = panels.length
    const { numFull: naturalNumFull, numStacked: naturalNumStacked } = naturalLayout

    let demotedPanelIndex: number | null = null
    if (activePanelIndex != null) {
      const activePanelIndexFromRight = panelCount - 1 - activePanelIndex
      const isActiveNaturallyFull = activePanelIndexFromRight < naturalNumFull
      if (!isActiveNaturallyFull && naturalNumFull > 0) {
        demotedPanelIndex = panelCount - 1
      }
    }

    const panelStates: Array<{ finalState: CalculatedPanelState["state"] }> = []
    let finalNumFull = 0
    let finalNumStacked = 0
    for (let i = 0; i < panelCount; i++) {
      const panelIndexFromRight = panelCount - 1 - i
      let naturalState: CalculatedPanelState["state"] = "hidden"
      if (panelIndexFromRight < naturalNumFull) naturalState = "full"
      else if (panelIndexFromRight < naturalNumFull + naturalNumStacked) naturalState = "stacked"

      let finalState: CalculatedPanelState["state"]
      if (i === activePanelIndex) finalState = "full"
      else if (i === demotedPanelIndex) finalState = "stacked"
      else finalState = naturalState

      panelStates.push({ finalState })
      if (finalState === "full") finalNumFull++
      else if (finalState === "stacked") finalNumStacked++
    }

    const finalTotalVisibleWidth =
      finalNumFull * config.panelWidth + finalNumStacked * config.stackedPanelWidth

    let currentRightOffset = -config.panelWidth
    const panelLayouts = new Map<string, PanelLayoutInfo>()

    for (let i = panelCount - 1; i >= 0; i--) {
      const panel = panels[i]
      const { finalState } = panelStates[i]
      if (finalState === "full") currentRightOffset += config.panelWidth
      else if (finalState === "stacked") currentRightOffset += config.stackedPanelWidth
      const position: PanelLayoutInfo["position"] = {
        right: currentRightOffset,
        zIndex: finalState === "hidden" ? -1 : i,
        baseWidth: config.panelWidth,
      }
      panelLayouts.set(panel.id, { position, state: finalState })
    }

    return { panelLayouts, totalVisibleWidth: finalTotalVisibleWidth }
  }
}

import { useCallback, useEffect, useMemo } from "react"

import {
  calculateNaturalLayout,
  configurePanelLayoutCalculator,
  type LayoutConfig,
  type PanelLayoutInfo,
} from "./helpers"
import type { CalculatedPanelState, UsePanelsArgs, UsePanelsReturn } from "./types"

const DEFAULT_PANEL_WIDTH = 504
const DEFAULT_MAX_PANELS = 5
const DEFAULT_MAX_VISIBLE_PANELS = 3
const DEFAULT_MAIN_VIEW_MIN_WIDTH = 600
const DEFAULT_BREAKPOINT = "sm"
const DEFAULT_STACKED_PANEL_WIDTH = 80

const breakpointValues: Record<NonNullable<UsePanelsArgs["breakpoint"]>, number> = {
  sm: 640,
  md: 768,
  lg: 1024,
  xl: 1280,
  "2xl": 1536,
}

export function usePanels({
  panels,
  containerWidth,
  activePanelId,
  panelWidth = DEFAULT_PANEL_WIDTH,
  maxPanels: _maxPanels = DEFAULT_MAX_PANELS,
  maxVisiblePanels = DEFAULT_MAX_VISIBLE_PANELS,
  mainViewMinWidth = DEFAULT_MAIN_VIEW_MIN_WIDTH,
  breakpoint,
  stackedPanelWidth = DEFAULT_STACKED_PANEL_WIDTH,
  onClose,
  onDockedPanelsChange,
  onActivateRequest,
}: UsePanelsArgs): UsePanelsReturn {
  const displayMode = useMemo((): "docked" | "overlay" => {
    const effectiveBreakpoint = breakpoint || DEFAULT_BREAKPOINT
    const threshold = breakpointValues[effectiveBreakpoint]
    return containerWidth > 0 && containerWidth <= threshold ? "overlay" : "docked"
  }, [containerWidth, breakpoint])

  const layoutConfig = useMemo(
    (): LayoutConfig => ({
      panelWidth,
      stackedPanelWidth,
      maxVisiblePanels,
      mainViewMinWidth,
      containerWidth,
    }),
    [panelWidth, stackedPanelWidth, maxVisiblePanels, mainViewMinWidth, containerWidth],
  )

  const calculateNaturalLayoutFn = useMemo(
    () => calculateNaturalLayout(layoutConfig),
    [layoutConfig],
  )
  const calculatePanelLayoutsFn = useMemo(
    () => configurePanelLayoutCalculator(layoutConfig),
    [layoutConfig],
  )

  const processedLayout = useMemo(() => {
    let calculatedPanelsData: CalculatedPanelState[]
    let finalTotalVisibleWidth = 0

    const activePanelIndex =
      activePanelId != null ? panels.findIndex((p) => p.id === activePanelId) : null
    const finalActiveIndex = activePanelIndex === -1 ? null : activePanelIndex

    if (displayMode === "overlay") {
      calculatedPanelsData = panels.map((panel, index) => ({
        id: panel.id,
        panelType: panel.id,
        content: panel.content,
        mode: "overlay",
        state: "full",
        position: {
          right: 0,
          zIndex: index,
          width: containerWidth || (typeof window !== "undefined" ? window.innerWidth : 0),
        },
      }))
      finalTotalVisibleWidth = 0
    } else {
      const naturalLayout = calculateNaturalLayoutFn(panels.length)

      const { panelLayouts, totalVisibleWidth } = calculatePanelLayoutsFn(
        panels,
        naturalLayout,
        finalActiveIndex,
      )
      finalTotalVisibleWidth = totalVisibleWidth

      calculatedPanelsData = panels.map((panel) => {
        const layoutInfo = panelLayouts.get(panel.id) as PanelLayoutInfo
        return {
          id: panel.id,
          panelType: panel.id,
          content: panel.content,
          mode: "docked" as const,
          state: layoutInfo.state,
          position: {
            right: layoutInfo.position.right,
            zIndex: layoutInfo.position.zIndex,
            width: layoutInfo.position.baseWidth,
          },
        }
      })
    }

    return { calculatedPanels: calculatedPanelsData, totalVisibleWidth: finalTotalVisibleWidth }
  }, [
    panels,
    layoutConfig,
    activePanelId,
    displayMode,
    containerWidth,
    calculateNaturalLayoutFn,
    calculatePanelLayoutsFn,
  ])

  const removePanel = useCallback(
    (panelId: string) => {
      onClose(panelId)
    },
    [onClose],
  )

  const activateStackedPanel = useCallback(
    (panelId: string) => {
      onActivateRequest(panelId)
    },
    [onActivateRequest],
  )

  useEffect(() => {
    if (displayMode === "docked") {
      const dockedPanelIds = processedLayout.calculatedPanels
        .filter((p) => p.mode === "docked" && p.state !== "hidden")
        .map((p) => p.id)
      onDockedPanelsChange?.(dockedPanelIds)
    }
  }, [processedLayout.calculatedPanels, displayMode, onDockedPanelsChange])

  return {
    calculatedPanels: processedLayout.calculatedPanels,
    displayMode,
    activePanelId,
    removePanel,
    activateStackedPanel,
    totalVisibleWidth: processedLayout.totalVisibleWidth,
  }
}

import { useCallback, useEffect, useMemo, useState } from "react"

import { useLocalStorage } from "../hooks/use-local-storage"

type SerializablePrimitive = string | number | boolean | null | undefined
interface SerializableObject extends Record<string, SerializableValue> {}
// eslint-disable-next-line @typescript-eslint/no-empty-object-type
interface SerializableArray extends Array<SerializableValue> {}
type SerializableValue = SerializablePrimitive | SerializableObject | SerializableArray

export type SerializableProps = Record<string, SerializableValue> | undefined

export interface PersistenceLayer {
  getOpenPanelTypes: () => string[]
  getPanelPropsMap: () => Record<string, SerializableProps>
  getActivePanelType: () => string | null
  setOpenPanelTypes: (types: string[]) => void
  setPanelPropsMap: (propsMap: Record<string, SerializableProps>) => void
  setActivePanelType: (type: string | null) => void
  subscribe: (callback: () => void) => () => void
}

export function useNoPersistence(): PersistenceLayer {
  const [openPanelTypes, setOpenPanelTypesState] = useState<string[]>([])
  const [panelPropsMap, setPanelPropsMapState] = useState<Record<string, SerializableProps>>({})
  const [activePanelType, setActivePanelTypeState] = useState<string | null>(null)

  const getOpenPanelTypes = useCallback(() => openPanelTypes, [openPanelTypes])
  const getPanelPropsMap = useCallback(() => panelPropsMap, [panelPropsMap])
  const getActivePanelType = useCallback(() => activePanelType, [activePanelType])

  const setOpenPanelTypes = useCallback((types: string[]) => {
    setOpenPanelTypesState(types)
  }, [])
  const setPanelPropsMap = useCallback((propsMap: Record<string, SerializableProps>) => {
    setPanelPropsMapState(propsMap)
  }, [])
  const setActivePanelType = useCallback((type: string | null) => {
    setActivePanelTypeState(type)
  }, [])

  const subscribe = useCallback((_callback: () => void) => () => {}, [])

  return useMemo(
    () => ({
      getOpenPanelTypes,
      getPanelPropsMap,
      getActivePanelType,
      setOpenPanelTypes,
      setPanelPropsMap,
      setActivePanelType,
      subscribe,
    }),
    [
      getOpenPanelTypes,
      getPanelPropsMap,
      getActivePanelType,
      setOpenPanelTypes,
      setPanelPropsMap,
      setActivePanelType,
      subscribe,
    ],
  )
}

export function useLocalStoragePersistence(localStorageKey: string): PersistenceLayer {
  const [openPanelTypes, setOpenPanelTypes] = useLocalStorage<string[]>(
    `${localStorageKey}-types`,
    [],
  )
  const [panelPropsMapStr, setPanelPropsMapStr] = useLocalStorage<string>(
    `${localStorageKey}-propsMap`,
    "{}",
  )
  const [activePanelType, setActivePanelType] = useLocalStorage<string | null>(
    `${localStorageKey}-activeType`,
    null,
  )

  const panelPropsMap = useMemo((): Record<string, SerializableProps> => {
    try {
      return JSON.parse(panelPropsMapStr) as Record<string, SerializableProps>
    } catch {
      return {}
    }
  }, [panelPropsMapStr])

  const getOpenPanelTypes = useCallback(() => openPanelTypes, [openPanelTypes])
  const getPanelPropsMap = useCallback(() => panelPropsMap, [panelPropsMap])
  const getActivePanelType = useCallback(() => activePanelType, [activePanelType])

  const setPanelPropsMap = useCallback(
    (propsMap: Record<string, SerializableProps>) => {
      try {
        const sanitizedPropsMap = JSON.parse(JSON.stringify(propsMap))
        setPanelPropsMapStr(JSON.stringify(sanitizedPropsMap))
      } catch {
        // ignore
      }
    },
    [setPanelPropsMapStr],
  )

  const subscribe = useCallback((callback: () => void) => {
    window.addEventListener("local-storage", callback)
    window.addEventListener("storage", callback)
    return () => {
      window.removeEventListener("local-storage", callback)
      window.removeEventListener("storage", callback)
    }
  }, [])

  return {
    getOpenPanelTypes,
    getPanelPropsMap,
    getActivePanelType,
    setOpenPanelTypes,
    setPanelPropsMap,
    setActivePanelType,
    subscribe,
  }
}

