import * as React from "react"
import { AnimatePresence } from "framer-motion"

import { cn } from "@/lib/utils"

import { Panel } from "./Panel"
import type { PanelsProps } from "./types"

export const Panels = React.forwardRef<HTMLDivElement, PanelsProps>(
  (
    {
      children,
      calculatedPanels,
      displayMode,
      totalVisibleWidth,
      removePanel,
      activateStackedPanel,
      mainViewMinWidth,
      containerWidth,
      className,
      ...props
    },
    ref,
  ) => {
    const mainViewAvailableWidth = containerWidth - totalVisibleWidth
    const mainViewStyle =
      displayMode === "docked"
        ? {
            minWidth: `${mainViewMinWidth}px`,
            width: `${Math.max(mainViewMinWidth, mainViewAvailableWidth)}px`,
            flexShrink: 0,
          }
        : { width: "100%" }

    return (
      <div
        ref={ref}
        className={cn("detail-panels-layout flex w-full overflow-hidden", className)}
        {...props}
      >
        <div
          className="detail-panels-main-view flex h-full min-h-0 min-w-0 flex-col overflow-hidden"
          style={mainViewStyle}
        >
          {children}
        </div>

        {displayMode === "docked" ? (
          <div
            className="detail-panels-panels-area relative h-full shrink-0"
            style={{ width: `${totalVisibleWidth}px` }}
          >
            <AnimatePresence mode="popLayout">
              {calculatedPanels.map((panel) => (
                <Panel
                  key={panel.id}
                  panel={panel}
                  onClose={removePanel}
                  onActivate={activateStackedPanel}
                />
              ))}
            </AnimatePresence>
          </div>
        ) : null}

        {displayMode === "overlay" ? (
          <AnimatePresence mode="popLayout">
            {calculatedPanels.map((panel) => (
              <Panel
                key={panel.id}
                panel={panel}
                onClose={removePanel}
                onActivate={activateStackedPanel}
              />
            ))}
          </AnimatePresence>
        ) : null}
      </div>
    )
  },
)

Panels.displayName = "Panels"

import * as React from "react"
import { motion } from "framer-motion"
import { XIcon } from "lucide-react"

import { Button } from "@/components/ui/button"
import { sidePanelSurfaceClassName } from "@/components/ui/side-panel-surface"
import { cn } from "@/lib/utils"

import type { CalculatedPanelState } from "./types"

interface PanelProps {
  panel: CalculatedPanelState
  onClose: (panelId: string) => void
  onActivate: (panelId: string) => void
}

const panelVariants = {
  initial: (position: CalculatedPanelState["position"]) => ({
    opacity: 0,
    right: -position.width,
  }),
  hidden: (position: CalculatedPanelState["position"]) => ({
    opacity: 0,
    right: position.right,
  }),
  full: (position: CalculatedPanelState["position"]) => ({
    opacity: 1,
    right: position.right,
  }),
  stacked: (position: CalculatedPanelState["position"]) => ({
    opacity: 1,
    right: position.right,
  }),
  exit: (position: CalculatedPanelState["position"]) => ({
    opacity: 0,
    right: -position.width,
  }),
}

const panelTransition = {
  type: "spring" as const,
  stiffness: 400,
  damping: 40,
}

export function Panel({ panel, onClose, onActivate }: PanelProps) {
  const { id, content, state, mode, position } = panel

  const handleClose = (event: React.MouseEvent) => {
    event.stopPropagation()
    onClose(id)
  }

  const handleClick = () => {
    if (state === "stacked") {
      onActivate(id)
    }
  }

  return (
    <motion.div
      key={id}
      variants={panelVariants}
      transition={panelTransition}
      custom={position}
      animate={state}
      initial="initial"
      exit="exit"
      onClick={state === "stacked" ? handleClick : undefined}
      className={cn("absolute inset-y-0 flex flex-col", {
        "fixed z-50": mode === "overlay",
      })}
      style={{
        zIndex: position.zIndex,
        overflow: "hidden",
        pointerEvents: state === "hidden" ? "none" : "auto",
      }}
    >
      <div
        className={sidePanelSurfaceClassName({
          inset: true,
          padded: false,
          className: "relative h-[calc(100%-2rem)] max-sm:h-full",
        })}
        style={{ width: `calc(${position.width}px - 2rem)` }}
      >
        {content}
        <Button
          type="button"
          size="icon-sm"
          variant="ghost"
          className="absolute top-3 right-3"
          onClick={handleClose}
        >
          <XIcon />
          <span className="sr-only">Close panel</span>
        </Button>
      </div>
    </motion.div>
  )
}

import * as React from "react"
import { useContext, useEffect, useRef, useState } from "react"
import type { ComponentType } from "react"

import { PanelsContext } from "./PanelsContext"
import { Panels as PanelsPresentational } from "./Panels"
import type { PersistenceLayer } from "./persistence"
import { PanelsProvider } from "./PanelsProvider"
import type { PanelsConfigProps } from "./types"

function useElementWidth(ref: React.RefObject<HTMLElement | null>) {
  const [width, setWidth] = useState(0)

  useEffect(() => {
    const element = ref.current
    if (!element) return

    const updateWidth = () => setWidth(element.getBoundingClientRect().width)
    updateWidth()

    const observer = new ResizeObserver(updateWidth)
    observer.observe(element)

    return () => observer.disconnect()
  }, [ref])

  return width
}

type PanelsLayoutProps<TPanelRegistry extends Record<string, ComponentType<unknown>>> =
  PanelsConfigProps & {
    persistenceLayer?: PersistenceLayer
    children: React.ReactNode
    panelTypes: TPanelRegistry
    className?: string
  }

const PanelsLayoutRenderer = React.forwardRef<
  HTMLDivElement,
  {
    children: React.ReactNode
    className?: string
  }
>(({ children, className }, ref) => {
  const context = useContext(PanelsContext)

  if (!context) {
    console.error(
      "PanelsLayoutRenderer: Context is missing. Ensure it is rendered within PanelsProvider.",
    )
    return null
  }

  const {
    calculatedPanels,
    displayMode,
    totalVisibleWidth,
    removePanel,
    activateStackedPanel,
    mainViewMinWidth,
    containerWidth,
  } = context

  return (
    <PanelsPresentational
      ref={ref}
      calculatedPanels={calculatedPanels}
      displayMode={displayMode}
      totalVisibleWidth={totalVisibleWidth}
      removePanel={removePanel}
      activateStackedPanel={activateStackedPanel}
      mainViewMinWidth={mainViewMinWidth ?? 300}
      containerWidth={containerWidth ?? 0}
      className={className}
    >
      {children}
    </PanelsPresentational>
  )
})
PanelsLayoutRenderer.displayName = "PanelsLayoutRenderer"

export const PanelsLayout = React.forwardRef<
  HTMLDivElement,
  PanelsLayoutProps<Record<string, ComponentType<unknown>>>
>(({ children, persistenceLayer, panelTypes, className, ...configProps }, forwardedRef) => {
  const containerRef = useRef<HTMLDivElement>(null)

  React.useImperativeHandle(forwardedRef, () => containerRef.current as HTMLDivElement)

  const containerWidth = useElementWidth(containerRef)

  const providerProps = {
    persistenceLayer,
    panelTypes,
    containerWidth,
    ...configProps,
  }

  return (
    <PanelsProvider<Record<string, ComponentType<unknown>>> {...providerProps}>
      <PanelsLayoutRenderer ref={containerRef} className={className}>
        {children}
      </PanelsLayoutRenderer>
    </PanelsProvider>
  )
})
PanelsLayout.displayName = "PanelsLayout"

