/** Great-circle distance between two WGS84 points in kilometers. */
export function haversineKm(
  lat1: number,
  lon1: number,
  lat2: number,
  lon2: number,
): number {
  const R = 6371
  const dLat = ((lat2 - lat1) * Math.PI) / 180
  const dLon = ((lon2 - lon1) * Math.PI) / 180
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos((lat1 * Math.PI) / 180) *
      Math.cos((lat2 * Math.PI) / 180) *
      Math.sin(dLon / 2) ** 2
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  return R * c
}

import type { CampingSpot, SurfSchool } from "@camping/domain-shared"

import { haversineKm } from "./geo.ts"

const MAX_NEIGHBORS = 8
const MAX_KM = 120

type WithCoords = { latitude: number; longitude: number }

export function nearbyCampingForSchool(
  school: SurfSchool,
  spots: CampingSpot[],
): CampingSpot[] {
  const origin: WithCoords = { latitude: school.latitude, longitude: school.longitude }
  const scored = spots
    .filter(
      (s): s is CampingSpot & WithCoords =>
        s.latitude != null &&
        s.longitude != null &&
        typeof s.latitude === "number" &&
        typeof s.longitude === "number",
    )
    .map((s) => ({
      spot: s,
      km: haversineKm(origin.latitude, origin.longitude, s.latitude, s.longitude),
      sameRegion: s.regionSlug === school.regionSlug,
    }))
    .filter(({ km }) => km <= MAX_KM)
    .sort((a, b) => {
      if (a.sameRegion !== b.sameRegion) return a.sameRegion ? -1 : 1
      return a.km - b.km
    })
    .slice(0, MAX_NEIGHBORS)
    .map(({ spot }) => spot)
  return scored
}

export function nearbySchoolsForCamping(
  spot: CampingSpot & WithCoords,
  schools: SurfSchool[],
): SurfSchool[] {
  return schools
    .map((s) => ({
      school: s,
      km: haversineKm(spot.latitude, spot.longitude, s.latitude, s.longitude),
      sameRegion: s.regionSlug === spot.regionSlug,
    }))
    .filter(({ km }) => km <= MAX_KM)
    .sort((a, b) => {
      if (a.sameRegion !== b.sameRegion) return a.sameRegion ? -1 : 1
      return a.km - b.km
    })
    .slice(0, MAX_NEIGHBORS)
    .map(({ school }) => school)
}

import type { CampingSpot, SurfSchool } from "@camping/domain-shared"
import {
  CardList,
  CoverView,
  IconButton,
  usePanelsContext,
} from "@camping/ui"
import { FavoriteButton } from "@camping/ui-lib"
import { ExternalLink, MapPin } from "lucide-react"
import { useMemo } from "react"

import { useUserOverlay } from "../hooks/use-user-overlay.ts"
import { getCampingSpots, getSurfSchools } from "../lib/catalog.ts"
import { haversineKm } from "../lib/geo.ts"
import { nearbyCampingForSchool, nearbySchoolsForCamping } from "../lib/nearby.ts"

const MAP_COVER =
  "https://images.unsplash.com/photo-1502680390469-be75c86b636f?auto=format&fit=crop&w=1600&q=80"

function regionLabel(slug: string) {
  return slug.replaceAll("-", " ")
}

function SurfSchoolDetailPanel({ slug }: { slug: string; panelType?: string }) {
  const { removePanel, openPanel } = usePanelsContext()
  const overlay = useUserOverlay()
  const school = useMemo(
    () => getSurfSchools().find((s) => s.slug === slug),
    [slug],
  )
  const spots = useMemo(() => getCampingSpots(), [])
  const neighbors = useMemo(
    () => (school ? nearbyCampingForSchool(school, spots) : []),
    [school, spots],
  )

  if (!school) {
    return (
      <CoverView
        title="School not found"
        colorScheme="background"
        className="h-full"
        primaryAction={
          <IconButton
            icon={(p) => <span {...p}>✕</span>}
            aria-label="Close"
            onClick={() => removePanel("surfSchoolDetail")}
          />
        }
      >
        <p className="text-sm text-muted-foreground">This entry is no longer in the catalog.</p>
      </CoverView>
    )
  }

  return (
    <CoverView
      title={school.name}
      colorScheme="primary"
      cover={MAP_COVER}
      className="h-full"
      primaryAction={
        <IconButton
          icon={(p) => <span {...p}>✕</span>}
          aria-label="Close panel"
          invertColors
          onClick={() => removePanel("surfSchoolDetail")}
        />
      }
      header={
        <p className="text-sm text-white/90">
          {regionLabel(school.regionSlug)} · {school.latitude.toFixed(3)}°,{" "}
          {school.longitude.toFixed(3)}°
        </p>
      }
      contentClassName="p-0"
    >
      <div className="space-y-4 px-4 pb-8 pt-2">
        <div className="flex flex-wrap items-center gap-2">
          <FavoriteButton
            active={overlay.isFavorite("surfSchool", school.slug)}
            label="Favorite surf school"
            onClick={() => overlay.toggleFavorite("surfSchool", school.slug)}
          />
          <a
            href={school.link}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex items-center gap-1.5 rounded-full border border-outline-variant/40 bg-background/90 px-3 py-1.5 text-xs font-semibold text-foreground hover:bg-muted"
          >
            <ExternalLink className="size-3.5" aria-hidden />
            Website
          </a>
          {school.gmaps ? (
            <a
              href={school.gmaps}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-1.5 rounded-full border border-outline-variant/40 bg-background/90 px-3 py-1.5 text-xs font-semibold text-foreground hover:bg-muted"
            >
              <MapPin className="size-3.5" aria-hidden />
              Maps
            </a>
          ) : null}
        </div>
        <p className="text-sm text-muted-foreground">{school.address}</p>
        <div>
          <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-outline">
            Camping nearby
          </p>
          {neighbors.length === 0 ? (
            <p className="text-sm text-muted-foreground">
              No campsites with coordinates in range yet.
            </p>
          ) : (
            <CardList
              items={neighbors.map((c) => ({ id: c.slug, spot: c }))}
              className="!block"
            >
              {(item) => (
                <button
                  key={item.id}
                  type="button"
                  onClick={() => openPanel("campingSpotDetail", { slug: item.spot.slug })}
                  className="flex flex-col rounded-xl border border-outline-variant/20 bg-card p-3 text-left text-card-foreground shadow-sm transition hover:border-primary/40"
                >
                  <span className="font-medium">{item.spot.name}</span>
                  <span className="text-xs text-muted-foreground">
                    {item.spot.regionSlug ? regionLabel(item.spot.regionSlug) : "Unknown region"}
                    {item.spot.latitude != null && item.spot.longitude != null
                      ? ` · ${haversineKm(
                          school.latitude,
                          school.longitude,
                          item.spot.latitude,
                          item.spot.longitude,
                        ).toFixed(0)} km`
                      : null}
                  </span>
                </button>
              )}
            </CardList>
          )}
        </div>
      </div>
    </CoverView>
  )
}

