import type { SurfSchool } from "@camping/domain-shared"
import L from "leaflet"
import "leaflet/dist/leaflet.css"
import { useEffect, useState } from "react"
import { CircleMarker, MapContainer, TileLayer, Tooltip, useMap } from "react-leaflet"

function useFixLeafletIcons() {
  useEffect(() => {
    const icon = new URL("leaflet/dist/images/marker-icon.png", import.meta.url).toString()
    const icon2x = new URL("leaflet/dist/images/marker-icon-2x.png", import.meta.url).toString()
    const shadow = new URL("leaflet/dist/images/marker-shadow.png", import.meta.url).toString()
    const Default = L.Icon.Default.prototype as unknown as { _getIconUrl?: () => string }
    delete Default._getIconUrl
    L.Icon.Default.mergeOptions({ iconUrl: icon, iconRetinaUrl: icon2x, shadowUrl: shadow })
  }, [])
}

function FitSchoolBounds({ schools }: { schools: SurfSchool[] }) {
  const map = useMap()
  useEffect(() => {
    if (schools.length === 0) return
    const bounds = L.latLngBounds(schools.map((s) => [s.latitude, s.longitude] as [number, number]))
    map.fitBounds(bounds, { padding: [28, 28], maxZoom: 9 })
  }, [map, schools])
  return null
}

export type ExploreSurfMapProps = {
  schools: SurfSchool[]
  onSelectSchool: (slug: string) => void
}

export function ExploreSurfMap({ schools, onSelectSchool }: ExploreSurfMapProps) {
  const [mounted, setMounted] = useState(false)
  useFixLeafletIcons()

  useEffect(() => {
    setMounted(true)
  }, [])

  if (!mounted) {
    return (
      <div className="flex h-[min(420px,55dvh)] w-full items-center justify-center rounded-3xl border border-outline-variant/20 bg-muted/40 text-sm text-muted-foreground">
        Loading map…
      </div>
    )
  }

  return (
    <div className="relative isolate h-[min(420px,55dvh)] w-full overflow-hidden rounded-3xl border border-outline-variant/20 shadow-inner">
      <MapContainer
        center={[46.2, -1.4]}
        zoom={6}
        className="h-full w-full [&_.leaflet-control-attribution]:text-[10px]"
        scrollWheelZoom
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />
        <FitSchoolBounds schools={schools} />
        {schools.map((school) => (
          <CircleMarker
            key={school.slug}
            center={[school.latitude, school.longitude]}
            radius={9}
            pathOptions={{
              color: "#1e3a8a",
              weight: 2,
              fillColor: "#60a5fa",
              fillOpacity: 0.85,
            }}
            eventHandlers={{
              click: () => onSelectSchool(school.slug),
            }}
          >
            <Tooltip direction="top" offset={[0, -6]} opacity={1}>
              <div className="max-w-[220px] space-y-1 px-0.5 py-0.5 text-xs">
                <p className="font-semibold text-foreground">{school.name}</p>
                <p className="text-muted-foreground">{school.address}</p>
                <p className="text-[10px] text-outline">
                  {school.regionSlug.replaceAll("-", " ")}
                </p>
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  )
}

