import {
  CardList,
  CoastalBadge,
  EditorialSectionHeader,
  FilterChip,
  FilterChipRow,
  MapPeekCard,
} from "@camping/ui-lib"
import { AppLayout, PanelsLayout, usePanelsContext } from "@camping/ui"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useMemo, useState } from "react"

import { explorePanelRegistry } from "../components/explore-panels.tsx"
import { ExploreSurfMap } from "../components/explore-map.tsx"
import { getRegions } from "../lib/catalog.ts"
import { driveFromAntwerpLabel } from "../lib/format.ts"
import { getSurfSchools } from "../lib/catalog.ts"

export const Route = createFileRoute("/explore")({
  component: ExploreRoute,
})

function ExploreMain() {
  const navigate = useNavigate()
  const { openPanel } = usePanelsContext<typeof explorePanelRegistry>()
  const regions = useMemo(() => getRegions().slice(0, 5), [])
  const schools = useMemo(() => getSurfSchools(), [])
  const [activeFilter, setActiveFilter] = useState("glass")
  const focus = regions[0]

  return (
    <AppLayout>
      <main className="flex min-h-0 flex-1 flex-col bg-background text-foreground">
        <section className="relative isolate shrink-0">
          <div className="flex flex-col gap-4 bg-gradient-to-b from-surface-container-low to-background px-4 pb-5 pt-4">
            <div>
              <EditorialSectionHeader
                kicker="Live beta"
                title="Explore surf schools on the map"
                actionSlot={<span className="text-outline">OpenStreetMap</span>}
              />
              <p className="mt-3 text-sm text-muted-foreground">
                Hover markers for a quick readout, tap for the full detail stack. Favorites
                stay in your browser overlay.
              </p>
            </div>
            <div className="rounded-[32px] border border-outline-variant/15 bg-surface-container-high/60 p-4 shadow-inner shadow-black/30 backdrop-blur-md">
              <div className="flex flex-wrap items-center gap-2">
                <CoastalBadge tone="hub">{schools.length} schools</CoastalBadge>
                <CoastalBadge tone="ghost">YAML + panels</CoastalBadge>
              </div>
              <div className="mt-4">
                <ExploreSurfMap
                  schools={schools}
                  onSelectSchool={(slug) => openPanel("surfSchoolDetail", { slug })}
                />
              </div>
            </div>
          </div>
        </section>

        <section className="min-h-0 flex-1 space-y-4 overflow-y-auto px-4 pb-8 pt-4">
          <p className="text-[10px] font-semibold uppercase tracking-[0.18em] text-outline">
            Quick filters
          </p>
          <FilterChipRow>
            {[
              { id: "glass", label: "Glass swell" },
              { id: "families", label: "Family sand" },
              { id: "push", label: "Push missions" },
            ].map((chip) => (
              <FilterChip
                key={chip.id}
                label={chip.label}
                selected={activeFilter === chip.id}
                onPress={() => {
                  setActiveFilter(chip.id)
                }}
              />
            ))}
          </FilterChipRow>

          {focus ? (
            <MapPeekCard
              imageSrc="https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=900&q=80"
              imageAlt={`Preview for ${focus.name}`}
              title={focus.name}
              subtitle={driveFromAntwerpLabel(focus)}
              ctaLabel="Open region details"
              onCtaPress={() => {
                void navigate({
                  to: "/regions/$slug",
                  params: { slug: focus.slug },
                })
              }}
            />
          ) : (
            <p className="text-sm text-muted-foreground">
              Add regions to the catalog to pin a map card.
            </p>
          )}
        </section>
      </main>
    </AppLayout>
  )
}

function ExploreRoute() {
  return (
    <PanelsLayout panelTypes={explorePanelRegistry} className="min-h-0 flex-1">
      <ExploreMain />
    </PanelsLayout>
  )
}

import {
  CoastalBottomNav,
  type CoastalBottomNavItem,
  CoastalTopBar,
} from "@camping/ui-lib"
import { AppProvider, AppShell } from "@camping/ui"
import { useNavigate, useRouterState } from "@tanstack/react-router"
import { Compass, Heart, Home, Map as MapIcon } from "lucide-react"
import type { ReactNode } from "react"

const NAV_ITEMS: CoastalBottomNavItem[] = [
  { id: "discover", label: "Discover", icon: Home },
  { id: "explore", label: "Explore", icon: MapIcon },
  { id: "saved", label: "Saved", icon: Heart },
  { id: "regions", label: "Regions", icon: Compass },
]

const ROUTE_BY_ID: Record<string, string> = {
  discover: "/",
  explore: "/explore",
  saved: "/saved",
  regions: "/regions",
}

export function AppChrome({ children }: { children: ReactNode }) {
  const navigate = useNavigate()
  const pathname = useRouterState({
    select: (s) => s.location.pathname,
  })

  const activeId =
    pathname === "/" || pathname === ""
      ? "discover"
      : pathname.startsWith("/explore")
        ? "explore"
        : pathname.startsWith("/saved")
          ? "saved"
          : pathname.startsWith("/regions")
            ? "regions"
            : "discover"

  return (
    <div className="flex min-h-dvh flex-col bg-background">
      <CoastalTopBar className="glass-coastal border-b border-outline-variant/10 shadow-none" />
      <AppShell className="flex min-h-0 flex-1 flex-col">
        <AppProvider>
          <div className="flex min-h-0 flex-1 flex-col pb-[calc(7rem+env(safe-area-inset-bottom))]">
            {children}
          </div>
        </AppProvider>
      </AppShell>
      <CoastalBottomNav
        className="glass-coastal border-t border-outline-variant/15 pb-[env(safe-area-inset-bottom)]"
        items={NAV_ITEMS}
        activeId={activeId}
        onItemPress={(id) => {
          const target = ROUTE_BY_ID[id]
          if (target) {
            void navigate({ to: target })
          }
        }}
      />
    </div>
  )
}

