/** Keys used in {@link panelRegistry} and `openPanel` / `removePanel`. */
export const SURF_SCHOOL_DETAIL_PANEL_TYPE = "surfSchoolDetail" as const;
export const CAMPING_SPOT_DETAIL_PANEL_TYPE = "campingSpotDetail" as const;

export const EXPLORE_PANEL_COVER_IMAGE =
	"https://images.unsplash.com/photo-1502680390469-be75c86b636f?auto=format&fit=crop&w=1600&q=80";

export function regionLabel(slug: string) {
	return slug.replaceAll("-", " ");
}

export function CloseGlyph(props: { className?: string }) {
	return (
		<span className={props.className} aria-hidden>
			✕
		</span>
	);
}

import type { CampingSpot } from "@camping/domain-shared";
import { CardList, CoverView, IconButton } from "@camping/ui";
import { FavoriteButton } from "@camping/ui-lib";
import { ExternalLink, MapPin } from "lucide-react";
import { useMemo } from "react";

import { useUserOverlay } from "../hooks/use-user-overlay.ts";
import { getCampingSpots, getSurfSchools } from "../lib/catalog.ts";
import { haversineKm } from "../lib/geo.ts";
import { nearbyCampingForSchool } from "../lib/nearby.ts";
import { CloseGlyph } from "./panel-chrome.tsx";
import {
	CAMPING_SPOT_DETAIL_PANEL_TYPE,
	EXPLORE_PANEL_COVER_IMAGE,
	regionLabel,
	SURF_SCHOOL_DETAIL_PANEL_TYPE,
} from "./panel-config.ts";
import { useExplorePanels } from "./useExplorePanels.ts";

export function SurfSchoolDetailPanel({
	slug,
}: {
	slug: string;
	panelType?: string;
}) {
	const { removePanel, openPanel } = useExplorePanels();
	const overlay = useUserOverlay();
	const school = useMemo(
		() => getSurfSchools().find((s) => s.slug === slug),
		[slug],
	);
	const spots = useMemo(() => getCampingSpots(), []);
	const neighbors = useMemo(
		() => (school ? nearbyCampingForSchool(school, spots) : []),
		[school, spots],
	);

	if (!school) {
		return (
			<CoverView
				title="School not found"
				colorScheme="background"
				className="h-full"
				primaryAction={
					<IconButton
						icon={CloseGlyph}
						aria-label="Close"
						onClick={() => removePanel(SURF_SCHOOL_DETAIL_PANEL_TYPE)}
					/>
				}
			>
				<p className="text-sm text-muted-foreground">
					This entry is no longer in the catalog.
				</p>
			</CoverView>
		);
	}

	return (
		<CoverView
			title={school.name}
			colorScheme="primary"
			cover={EXPLORE_PANEL_COVER_IMAGE}
			className="h-full"
			primaryAction={
				<IconButton
					icon={CloseGlyph}
					aria-label="Close panel"
					invertColors
					onClick={() => removePanel(SURF_SCHOOL_DETAIL_PANEL_TYPE)}
				/>
			}
			header={
				<p className="text-sm text-white/90">
					{regionLabel(school.regionSlug)} · {school.latitude.toFixed(3)}°,{" "}
					{school.longitude.toFixed(3)}°
				</p>
			}
			contentClassName="p-0"
		>
			<div className="space-y-4 px-4 pb-8 pt-2">
				<div className="flex flex-wrap items-center gap-2">
					<FavoriteButton
						active={overlay.isFavorite("surfSchool", school.slug)}
						label="Favorite surf school"
						onClick={() => overlay.toggleFavorite("surfSchool", school.slug)}
					/>
					<a
						href={school.link}
						target="_blank"
						rel="noopener noreferrer"
						className="inline-flex items-center gap-1.5 rounded-full border border-outline-variant/40 bg-background/90 px-3 py-1.5 text-xs font-semibold text-foreground hover:bg-muted"
					>
						<ExternalLink className="size-3.5" aria-hidden />
						Website
					</a>
					{school.gmaps ? (
						<a
							href={school.gmaps}
							target="_blank"
							rel="noopener noreferrer"
							className="inline-flex items-center gap-1.5 rounded-full border border-outline-variant/40 bg-background/90 px-3 py-1.5 text-xs font-semibold text-foreground hover:bg-muted"
						>
							<MapPin className="size-3.5" aria-hidden />
							Maps
						</a>
					) : null}
				</div>
				<p className="text-sm text-muted-foreground">{school.address}</p>
				<div>
					<p className="mb-2 text-xs font-semibold uppercase tracking-wide text-outline">
						Camping nearby
					</p>
					{neighbors.length === 0 ? (
						<p className="text-sm text-muted-foreground">
							No campsites with coordinates in range yet.
						</p>
					) : (
						<CardList
							items={neighbors.map((c) => ({ id: c.slug, spot: c }))}
							className="!block"
						>
							{(item) => (
								<button
									key={item.id}
									type="button"
									onClick={() =>
										openPanel(CAMPING_SPOT_DETAIL_PANEL_TYPE, {
											slug: item.spot.slug,
										})
									}
									className="flex flex-col rounded-xl border border-outline-variant/20 bg-card p-3 text-left text-card-foreground shadow-sm transition hover:border-primary/40"
								>
									<span className="font-medium">{item.spot.name}</span>
									<span className="text-xs text-muted-foreground">
										{item.spot.regionSlug
											? regionLabel(item.spot.regionSlug)
											: "Unknown region"}
										{item.spot.latitude != null && item.spot.longitude != null
											? ` · ${haversineKm(
													school.latitude,
													school.longitude,
													item.spot.latitude,
													item.spot.longitude,
												).toFixed(0)} km`
											: null}
									</span>
								</button>
							)}
						</CardList>
					)}
				</div>
			</div>
		</CoverView>
	);
}

import type { CampingSpot } from "@camping/domain-shared";
import { CardList, CoverView, IconButton } from "@camping/ui";
import { FavoriteButton } from "@camping/ui-lib";
import { ExternalLink } from "lucide-react";
import { useMemo } from "react";

import { useUserOverlay } from "../hooks/use-user-overlay.ts";
import { getCampingSpots, getSurfSchools } from "../lib/catalog.ts";
import { haversineKm } from "../lib/geo.ts";
import { nearbySchoolsForCamping } from "../lib/nearby.ts";
import { CloseGlyph } from "./panel-chrome.tsx";
import {
	CAMPING_SPOT_DETAIL_PANEL_TYPE,
	EXPLORE_PANEL_COVER_IMAGE,
	regionLabel,
	SURF_SCHOOL_DETAIL_PANEL_TYPE,
} from "./panel-config.ts";
import { useExplorePanels } from "./useExplorePanels.ts";

export function CampingSpotDetailPanel({
	slug,
}: {
	slug: string;
	panelType?: string;
}) {
	const { removePanel, openPanel } = useExplorePanels();
	const overlay = useUserOverlay();
	const spot = useMemo(
		() => getCampingSpots().find((c) => c.slug === slug),
		[slug],
	);
	const schools = useMemo(() => getSurfSchools(), []);
	const neighbors = useMemo(() => {
		if (!spot || spot.latitude == null || spot.longitude == null) return [];
		return nearbySchoolsForCamping(
			spot as CampingSpot & { latitude: number; longitude: number },
			schools,
		);
	}, [spot, schools]);

	if (!spot) {
		return (
			<CoverView
				title="Campsite not found"
				colorScheme="background"
				className="h-full"
				primaryAction={
					<IconButton
						icon={CloseGlyph}
						aria-label="Close"
						onClick={() => removePanel(CAMPING_SPOT_DETAIL_PANEL_TYPE)}
					/>
				}
			>
				<p className="text-sm text-muted-foreground">
					This entry is no longer in the catalog.
				</p>
			</CoverView>
		);
	}

	return (
		<CoverView
			title={spot.name}
			colorScheme="card"
			cover={EXPLORE_PANEL_COVER_IMAGE}
			className="h-full"
			primaryAction={
				<IconButton
					icon={CloseGlyph}
					aria-label="Close panel"
					invertColors
					onClick={() => removePanel(CAMPING_SPOT_DETAIL_PANEL_TYPE)}
				/>
			}
			header={
				<p className="text-sm text-white/90">
					{spot.regionSlug ? regionLabel(spot.regionSlug) : "Uncatalogued"}
				</p>
			}
			contentClassName="p-0"
		>
			<div className="space-y-4 px-4 pb-8 pt-2">
				<div className="flex flex-wrap items-center gap-2">
					<FavoriteButton
