import type { SurfSchool } from "@camping/domain-shared";
import { cn } from "@camping/ui";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import { useEffect, useState } from "react";
import {
	CircleMarker,
	MapContainer,
	TileLayer,
	Tooltip,
	useMap,
} from "react-leaflet";

function FitSchoolBounds({ schools }: { schools: SurfSchool[] }) {
	const map = useMap();
	useEffect(() => {
		if (schools.length === 0) return;
		const bounds = L.latLngBounds(
			schools.map((s) => [s.latitude, s.longitude] as [number, number]),
		);
		map.fitBounds(bounds, { padding: [24, 24], maxZoom: 10 });
	}, [map, schools]);
	return null;
}

/** Re-fit tiles when the map container is resized (e.g. flex layout settling). */
function MapResizeSync() {
	const map = useMap();
	useEffect(() => {
		const run = () => map.invalidateSize({ animate: false });
		const id = requestAnimationFrame(run);
		const parent = map.getContainer().parentElement;
		if (!parent) {
			return () => cancelAnimationFrame(id);
		}
		const ro = new ResizeObserver(run);
		ro.observe(parent);
		return () => {
			cancelAnimationFrame(id);
			ro.disconnect();
		};
	}, [map]);
	return null;
}

export type ExploreSurfMapProps = {
	schools: SurfSchool[];
	onSelectSchool: (slug: string) => void;
	className?: string;
};

export function ExploreSurfMap({
	schools,
	onSelectSchool,
	className,
}: ExploreSurfMapProps) {
	const [mounted, setMounted] = useState(false);

	useEffect(() => {
		setMounted(true);
	}, []);

	const shell = "relative flex min-h-0 w-full min-w-0 flex-1 flex-col overflow-hidden bg-background";

	if (!mounted) {
		return (
			<div
				className={cn(
					shell,
					"items-center justify-center text-sm text-muted-foreground",
					className,
				)}
			>
				Loading map…
			</div>
		);
	}

	return (
		<div className={cn(shell, className)}>
			<MapContainer
				center={[46.2, -1.4]}
				zoom={6}
				className="z-0 min-h-0 flex-1 [&_.leaflet-container]:h-full [&_.leaflet-container]:w-full [&_.leaflet-container]:bg-background [&_.leaflet-control-attribution]:text-[10px]"
				scrollWheelZoom
				style={{ height: "100%", width: "100%" }}
			>
				<TileLayer
					attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
					url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
				/>
				<FitSchoolBounds schools={schools} />
				<MapResizeSync />
				{schools.map((school) => (
					<CircleMarker
						key={school.slug}
						center={[school.latitude, school.longitude]}
						radius={9}
						pathOptions={{
							color: "#1e3a8a",
							weight: 2,
							fillColor: "#60a5fa",
							fillOpacity: 0.85,
						}}
						eventHandlers={{
							click: () => onSelectSchool(school.slug),
						}}
					>
						<Tooltip direction="top" offset={[0, -6]} opacity={1}>
							<div className="max-w-[220px] space-y-1 px-0.5 py-0.5 text-xs">
								<p className="font-semibold text-foreground">{school.name}</p>
								<p className="text-muted-foreground">{school.address}</p>
								<p className="text-[10px] text-outline">
									{school.regionSlug.replaceAll("-", " ")}
								</p>
							</div>
						</Tooltip>
					</CircleMarker>
				))}
			</MapContainer>
		</div>
	);
}

