import type { SerializableProps } from "./persistence"

/**
 * Query keys for stacked panels in the URL (Procertus sewdn / `useUrlQueryPersistence`).
 * The optional `panelProps` map is JSON-serialized in the query string.
 */
export const PANELS_URL_QUERY_KEYS = {
  stack: "panels",
  active: "activePanel",
  props: "panelProps",
} as const

export type PanelsUrlSearchFields = {
  [PANELS_URL_QUERY_KEYS.stack]?: string
  [PANELS_URL_QUERY_KEYS.active]?: string
  [PANELS_URL_QUERY_KEYS.props]?: string
}

export type ParsedPanelsUrlSearch = {
  openPanelTypes: string[]
  activePanelType: string | null
  panelPropsMap: Record<string, SerializableProps>
}

export function parsePanelsUrlSearch(
  fields: Partial<PanelsUrlSearchFields> | Record<string, string | undefined>,
): ParsedPanelsUrlSearch {
  const panels = fields[PANELS_URL_QUERY_KEYS.stack]
  const openPanelTypes = typeof panels === "string" && panels.length > 0 ? panels.split(",") : []
  const activeRaw = fields[PANELS_URL_QUERY_KEYS.active]
  const activePanelType = typeof activeRaw === "string" && activeRaw.length > 0 ? activeRaw : null
  const propsRaw = fields[PANELS_URL_QUERY_KEYS.props]
  let panelPropsMap: Record<string, SerializableProps> = {}
  if (typeof propsRaw === "string" && propsRaw.length > 0) {
    try {
      panelPropsMap = JSON.parse(propsRaw) as Record<string, SerializableProps>
    } catch {
      panelPropsMap = {}
    }
  }
  return { openPanelTypes, activePanelType, panelPropsMap }
}

/**
 * Merges panel stack / active / props into a search object while preserving unrelated keys.
 */
export function mergePanelsIntoSearch<T extends Record<string, string | undefined>>(
  prev: T,
  state: ParsedPanelsUrlSearch,
): T {
  const next = { ...prev }
  const r = next as Record<string, string | undefined>
  if (state.openPanelTypes.length > 0) {
    r[PANELS_URL_QUERY_KEYS.stack] = state.openPanelTypes.join(",")
  } else {
    delete r[PANELS_URL_QUERY_KEYS.stack]
  }
  if (state.activePanelType) {
    r[PANELS_URL_QUERY_KEYS.active] = state.activePanelType
  } else {
    delete r[PANELS_URL_QUERY_KEYS.active]
  }
  try {
    const sanitized = JSON.parse(JSON.stringify(state.panelPropsMap)) as Record<
      string,
      SerializableProps
    >
    if (Object.keys(sanitized).length > 0) {
      r[PANELS_URL_QUERY_KEYS.props] = JSON.stringify(sanitized)
    } else {
      delete r[PANELS_URL_QUERY_KEYS.props]
    }
  } catch {
    delete r[PANELS_URL_QUERY_KEYS.props]
  }
  return next
}

import {
	PANELS_URL_QUERY_KEYS,
	type PanelsUrlSearchFields,
	parsePanelsUrlSearch,
} from "@camping/ui";

export type ExplorePanelsSearch = PanelsUrlSearchFields;

export function validateExplorePanelsSearch(
	raw: Record<string, unknown>,
): ExplorePanelsSearch {
	return {
		[PANELS_URL_QUERY_KEYS.stack]:
			typeof raw[PANELS_URL_QUERY_KEYS.stack] === "string"
				? raw[PANELS_URL_QUERY_KEYS.stack]
				: undefined,
		[PANELS_URL_QUERY_KEYS.active]:
			typeof raw[PANELS_URL_QUERY_KEYS.active] === "string"
				? raw[PANELS_URL_QUERY_KEYS.active]
				: undefined,
		[PANELS_URL_QUERY_KEYS.props]:
			typeof raw[PANELS_URL_QUERY_KEYS.props] === "string"
				? raw[PANELS_URL_QUERY_KEYS.props]
				: undefined,
	};
}

export function parseExplorePanelsSearch(search: ExplorePanelsSearch): ReturnType<
	typeof parsePanelsUrlSearch
> {
	return parsePanelsUrlSearch(search)
}

import type { PersistenceLayer, SerializableProps } from "@camping/ui";
import { mergePanelsIntoSearch, parsePanelsUrlSearch } from "@camping/ui";
import { getRouteApi } from "@tanstack/react-router";
import { useCallback, useEffect, useMemo, useRef } from "react";

import type { ExplorePanelsSearch } from "./explore-url-search.ts";

const exploreRoute = getRouteApi("/explore");

/**
 * Persists {@link PersistenceLayer} panel state in `/explore` URL search params,
 * matching Procertus sewdn `useUrlQueryPersistence` / `PANELS_URL_QUERY_KEYS`.
 */
export function useExploreUrlPersistence(): PersistenceLayer {
	const search = exploreRoute.useSearch();
	const navigate = exploreRoute.useNavigate();

	const { openPanelTypes, activePanelType, panelPropsMap } = useMemo(
		() => parsePanelsUrlSearch(search),
		[search],
	);

	const stateRef = useRef({
		openPanelTypes,
		activePanelType,
		panelPropsMap,
	});

	useEffect(() => {
		stateRef.current = {
			openPanelTypes,
			activePanelType,
			panelPropsMap,
		};
	}, [openPanelTypes, activePanelType, panelPropsMap]);

	const updateUrl = useCallback(() => {
		navigate({
			search: (prev: ExplorePanelsSearch) =>
				mergePanelsIntoSearch(prev, stateRef.current),
			replace: true,
		});
	}, [navigate]);

	const setOpenPanelTypes = useCallback(
		(types: string[]) => {
			stateRef.current = { ...stateRef.current, openPanelTypes: types };
			updateUrl();
		},
		[updateUrl],
	);

	const setPanelPropsMap = useCallback(
		(propsMap: Record<string, SerializableProps>) => {
			stateRef.current = { ...stateRef.current, panelPropsMap: propsMap };
			updateUrl();
		},
		[updateUrl],
	);

	const setActivePanelType = useCallback(
		(type: string | null) => {
			stateRef.current = { ...stateRef.current, activePanelType: type };
			updateUrl();
		},
		[updateUrl],
	);

	const getOpenPanelTypes = useCallback(() => openPanelTypes, [openPanelTypes]);
	const getPanelPropsMap = useCallback(() => panelPropsMap, [panelPropsMap]);
	const getActivePanelType = useCallback(() => activePanelType, [activePanelType]);

	const subscribe = useCallback((_callback: () => void) => () => {}, []);

	return useMemo(
		() => ({
			getOpenPanelTypes,
			getPanelPropsMap,
			getActivePanelType,
			setOpenPanelTypes,
			setPanelPropsMap,
			setActivePanelType,
			subscribe,
		}),
		[
			getOpenPanelTypes,
			getPanelPropsMap,
			getActivePanelType,
			setOpenPanelTypes,
			setPanelPropsMap,
			setActivePanelType,
			subscribe,
		],
	);
}

