import { useCallback, useEffect, useMemo, useState } from "react";

const STORAGE_KEY = "camping.frontend-web.explore.selectedRegionSlugs";

function readStorage(): string[] {
	if (typeof window === "undefined") return [];
	try {
		const raw = window.localStorage.getItem(STORAGE_KEY);
		if (raw == null || raw === "") return [];
		const parsed: unknown = JSON.parse(raw);
		if (!Array.isArray(parsed)) return [];
		return parsed.filter((x): x is string => typeof x === "string");
	} catch {
		return [];
	}
}

function writeStorage(slugs: readonly string[]) {
	try {
		window.localStorage.setItem(STORAGE_KEY, JSON.stringify(slugs));
	} catch {
		// ignore quota / private mode
	}
}

function sanitize(slugs: readonly string[], allowed: ReadonlySet<string>): string[] {
	const seen = new Set<string>();
	const out: string[] = [];
	for (const s of slugs) {
		if (!allowed.has(s) || seen.has(s)) continue;
		seen.add(s);
		out.push(s);
	}
	out.sort();
	return out;
}

export function passesExploreRegionFilter(
	regionSlug: string | undefined,
	selectedRegionSlugs: readonly string[],
): boolean {
	if (selectedRegionSlugs.length === 0) return true;
	if (regionSlug == null || regionSlug === "") return false;
	return selectedRegionSlugs.includes(regionSlug);
}

/**
 * Persisted multi-select of region slugs for the explore map.
 * Empty selection means no filter (show all regions).
 */
export function useExploreRegionFilter(allRegionSlugs: readonly string[]) {
	const allowed = useMemo(() => new Set(allRegionSlugs), [allRegionSlugs]);

	const [selectedRegionSlugs, setSelectedRegionSlugs] = useState<string[]>([]);

	useEffect(() => {
		setSelectedRegionSlugs(sanitize(readStorage(), allowed));
	}, [allowed]);

	const commit = useCallback(
		(updater: (prev: string[]) => string[]) => {
			setSelectedRegionSlugs((prev) => {
				const next = sanitize(updater(prev), allowed);
				writeStorage(next);
				return next;
			});
		},
		[allowed],
	);

	const toggleRegionSlug = useCallback(
		(slug: string, checked: boolean) => {
			if (!allowed.has(slug)) return;
			if (checked) {
				commit((prev) => {
					if (prev.length === 0) return [slug];
					if (prev.includes(slug)) return prev;
					return [...prev, slug];
				});
			} else {
				commit((prev) => prev.filter((s) => s !== slug));
			}
		},
		[allowed, commit],
	);

	const clearRegionFilter = useCallback(() => {
		commit(() => []);
	}, [commit]);

	const passesRegionFilter = useCallback(
		(regionSlug: string | undefined) =>
			passesExploreRegionFilter(regionSlug, selectedRegionSlugs),
		[selectedRegionSlugs],
	);

	return {
		selectedRegionSlugs,
		toggleRegionSlug,
		clearRegionFilter,
		passesRegionFilter,
		regionFilterActive: selectedRegionSlugs.length > 0,
	};
}

import type { Region } from "@camping/domain-shared";
