					<PopoverTitle>Regions</PopoverTitle>
					<PopoverDescription>
						With none selected, every region is shown. Choose one or more to limit
						surf schools and camping spots to those areas.
					</PopoverDescription>
				</PopoverHeader>
				<div className="flex flex-wrap gap-2">
					<Button type="button" size="xs" variant="outline" onClick={clearRegionFilter}>
						Show all regions
					</Button>
				</div>
				<ScrollArea className="h-[min(20rem,50vh)] pr-2">
					<ul className="flex flex-col gap-1.5 py-1">
						{regions.map((r) => (
							<li key={r.slug}>
								<label className="flex cursor-pointer items-start gap-2 rounded-md px-1 py-1 hover:bg-muted/60">
									<Checkbox
										className="mt-0.5"
										checked={selectedRegionSlugs.includes(r.slug)}
										onCheckedChange={(c) => toggleRegionSlug(r.slug, c === true)}
