import type { CampingSpot, Region, SurfSchool } from "@camping/domain-shared";
import { cn } from "@camping/ui";
import { Button } from "@camping/ui/components/ui/button";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import { useEffect, useMemo, useState } from "react";
import {
	CircleMarker,
	MapContainer,
	TileLayer,
	Tooltip,
	useMap,
} from "react-leaflet";

import { useExploreRegionFilter } from "../hooks/use-explore-region-filter.ts";
import { ExploreRegionFilterMenu } from "./explore-region-filter-menu.tsx";

function isCampingSpotOnMap(
	spot: CampingSpot,
): spot is CampingSpot & { latitude: number; longitude: number } {
	return (
		typeof spot.latitude === "number" && typeof spot.longitude === "number"
	);
}

function FitVisibleBounds({ points }: { points: readonly [number, number][] }) {
	const map = useMap();
	useEffect(() => {
		if (points.length === 0) return;
		const bounds = L.latLngBounds(points);
		map.fitBounds(bounds, { padding: [24, 24], maxZoom: 10 });
	}, [map, points]);
	return null;
}

/** Re-fit tiles when the map container is resized (e.g. flex layout settling). */
function MapResizeSync() {
	const map = useMap();
	useEffect(() => {
		const run = () => map.invalidateSize({ animate: false });
		const id = requestAnimationFrame(run);
		const el = map.getContainer();
		const ro = new ResizeObserver(run);
		ro.observe(el);
		return () => {
			cancelAnimationFrame(id);
			ro.disconnect();
		};
	}, [map]);
	return null;
}

export type ExploreSurfMapProps = {
	regions: readonly Region[];
	schools: SurfSchool[];
	campingSpots: CampingSpot[];
	onSelectSchool: (slug: string) => void;
	onSelectCampingSpot: (slug: string) => void;
	className?: string;
};

export function ExploreSurfMap({
	regions,
	schools,
	campingSpots,
	onSelectSchool,
	onSelectCampingSpot,
	className,
}: ExploreSurfMapProps) {
	const [mounted, setMounted] = useState(false);
	const [showSurfSchools, setShowSurfSchools] = useState(true);
	const [showCampingSpots, setShowCampingSpots] = useState(true);

	const regionSlugs = useMemo(() => regions.map((r) => r.slug), [regions]);
	const regionFilter = useExploreRegionFilter(regionSlugs);

	useEffect(() => {
		setMounted(true);
	}, []);

	const spotsOnMap = useMemo(
		() => campingSpots.filter(isCampingSpotOnMap),
		[campingSpots],
	);

	const schoolsOnMap = useMemo(
		() => schools.filter((s) => regionFilter.passesRegionFilter(s.regionSlug)),
		[schools, regionFilter.passesRegionFilter],
	);

	const campingOnMap = useMemo(
		() => spotsOnMap.filter((s) => regionFilter.passesRegionFilter(s.regionSlug)),
		[spotsOnMap, regionFilter.passesRegionFilter],
	);

	const fitBoundsPoints = useMemo((): [number, number][] => {
		const pts: [number, number][] = [];
		if (showSurfSchools) {
			for (const s of schoolsOnMap) {
				pts.push([s.latitude, s.longitude]);
			}
		}
		if (showCampingSpots) {
			for (const s of campingOnMap) {
				pts.push([s.latitude, s.longitude]);
			}
		}
		return pts;
	}, [showSurfSchools, showCampingSpots, schoolsOnMap, campingOnMap]);

	const shell =
		"relative flex min-h-0 w-full min-w-0 flex-1 flex-col overflow-hidden bg-background";

	if (!mounted) {
		return (
			<div
				className={cn(
					shell,
					"items-center justify-center text-sm text-muted-foreground",
					className,
				)}
			>
				Loading map…
			</div>
		);
	}

	return (
		<div className={cn(shell, className)}>
			<div className="relative flex min-h-0 flex-1 flex-col">
				<div className="pointer-events-none absolute top-3 left-3 z-[1000] flex max-w-[calc(100%-1.5rem)] flex-wrap gap-2">
					<ExploreRegionFilterMenu
						regions={regions}
						selectedRegionSlugs={regionFilter.selectedRegionSlugs}
						toggleRegionSlug={regionFilter.toggleRegionSlug}
						clearRegionFilter={regionFilter.clearRegionFilter}
						selectAllRegionSlugs={regionFilter.selectAllRegionSlugs}
					/>
					<Button
						type="button"
						size="sm"
						variant={showSurfSchools ? "secondary" : "outline"}
						className="pointer-events-auto shadow-md backdrop-blur-sm"
						aria-pressed={showSurfSchools}
						onClick={() => setShowSurfSchools((v) => !v)}
					>
						Surf schools
					</Button>
					<Button
						type="button"
						size="sm"
						variant={showCampingSpots ? "secondary" : "outline"}
						className="pointer-events-auto shadow-md backdrop-blur-sm"
						aria-pressed={showCampingSpots}
						onClick={() => setShowCampingSpots((v) => !v)}
					>
						Camping
					</Button>
				</div>
				<MapContainer
					center={[46.2, -1.4]}
					zoom={6}
					className="relative z-0 min-h-0 w-full flex-1 [&_.leaflet-container]:h-full [&_.leaflet-container]:w-full [&_.leaflet-container]:bg-background [&_.leaflet-control-attribution]:text-[10px]"
					scrollWheelZoom
					style={{ height: "100%", width: "100%", minHeight: 0 }}
				>
					<TileLayer
						attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
						url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
					/>
					<FitVisibleBounds points={fitBoundsPoints} />
					<MapResizeSync />
					{showSurfSchools
						? schoolsOnMap.map((school) => (
								<CircleMarker
									key={`school-${school.slug}`}
									center={[school.latitude, school.longitude]}
									radius={9}
									pathOptions={{
										color: "#1e3a8a",
										weight: 2,
										fillColor: "#60a5fa",
										fillOpacity: 0.85,
									}}
									eventHandlers={{
										click: () => onSelectSchool(school.slug),
									}}
								>
									<Tooltip direction="top" offset={[0, -6]} opacity={1}>
										<div className="max-w-[220px] space-y-1 px-0.5 py-0.5 text-xs">
											<p className="font-semibold text-foreground">
												{school.name}
											</p>
											<p className="text-muted-foreground">{school.address}</p>
											<p className="text-[10px] text-outline">
												{school.regionSlug.replaceAll("-", " ")}
											</p>
										</div>
									</Tooltip>
								</CircleMarker>
							))
						: null}
					{showCampingSpots
						? campingOnMap.map((spot) => (
								<CircleMarker
									key={`camping-${spot.slug}`}
									center={[spot.latitude, spot.longitude]}
									radius={8}
									pathOptions={{
										color: "#14532d",
										weight: 2,
										fillColor: "#4ade80",
										fillOpacity: 0.88,
									}}
									eventHandlers={{
										click: () => onSelectCampingSpot(spot.slug),
									}}
								>
									<Tooltip direction="top" offset={[0, -6]} opacity={1}>
										<div className="max-w-[220px] space-y-1 px-0.5 py-0.5 text-xs">
											<p className="font-semibold text-foreground">
												{spot.name}
											</p>
											{spot.address ? (
												<p className="text-muted-foreground">{spot.address}</p>
											) : null}
											<p className="text-[10px] text-outline">
												{spot.kind}
												{spot.regionSlug
													? ` · ${spot.regionSlug.replaceAll("-", " ")}`
													: ""}
											</p>
										</div>
									</Tooltip>
								</CircleMarker>
							))
						: null}
				</MapContainer>
			</div>
		</div>
	);
}

