import {
	CURRENT_USER_CAMPING_STATE_VERSION,
	type DraftCampingSpot,
	decodeUserCampingState,
	type EntityKind,
	EntityRef,
	emptyUserCampingState,
	encodeEntityRefKey,
	favoriteKey,
	type ReviewEntry,
	type UserCampingState,
} from "@camping/domain-shared";
import { Option } from "effect";
import {
	createContext,
	type ReactNode,
	useCallback,
	useContext,
	useEffect,
	useMemo,
	useState,
} from "react";

const STORAGE_KEY = "camping:user-camping-state-v1";

const serializeState = (state: UserCampingState): string =>
	JSON.stringify({
		version: state.version,
		favorites: state.favorites,
		reviews: Object.fromEntries(
			Object.entries(state.reviews).map(([k, v]) => [
				k,
				{
					ref: { type: v.ref.type, id: v.ref.id },
					rating: v.rating,
					text: v.text,
					createdAt: v.createdAt,
					updatedAt: v.updatedAt,
				},
			]),
		),
		draftCampingSpots: Object.fromEntries(
			Object.entries(state.draftCampingSpots).map(([k, v]) => [
				k,
				{
					slug: v.slug,
					name: v.name,
					kind: v.kind,
					regionSlug: v.regionSlug,
					address: v.address,
					latitude: v.latitude,
					longitude: v.longitude,
					link: v.link,
					notes: v.notes,
					createdAt: v.createdAt,
					updatedAt: v.updatedAt,
				},
			]),
		),
	});

const deserializeState = (raw: string): UserCampingState => {
	const parsed = JSON.parse(raw) as unknown;
	const decoded = decodeUserCampingState(parsed);
	return Option.getOrElse(decoded, () => emptyUserCampingState());
};

export type MergeMode = "replace" | "merge";

export type UserOverlayApi = {
	hydrated: boolean;
	state: UserCampingState;
	persist: (next: UserCampingState) => void;
	exportJson: () => string;
	importJson: (raw: string, mode: MergeMode) => void;
	clear: () => void;
	toggleFavorite: (type: EntityKind, id: string) => void;
	isFavorite: (type: EntityKind, id: string) => boolean;
	setReview: (review: ReviewEntry) => void;
	upsertDraftCampingSpot: (draft: DraftCampingSpot) => void;
	removeDraftCampingSpot: (slug: string) => void;
};

const UserOverlayContext = createContext<UserOverlayApi | null>(null);

export function UserOverlayProvider({ children }: { children: ReactNode }) {
	const [hydrated, setHydrated] = useState(false);
	const [state, setState] = useState<UserCampingState>(() =>
		emptyUserCampingState(),
	);

	const loadFromStorage = useCallback(() => {
		if (typeof window === "undefined") return;
		try {
			const raw = window.localStorage.getItem(STORAGE_KEY);
			if (raw) setState(deserializeState(raw));
			else setState(emptyUserCampingState());
		} catch {
			// ignore
		}
	}, []);

	useEffect(() => {
		loadFromStorage();
		setHydrated(true);
	}, [loadFromStorage]);

	useEffect(() => {
		const onStorage = (event: StorageEvent) => {
			if (event.key !== STORAGE_KEY) return;
			if (event.newValue == null) {
				setState(emptyUserCampingState());
				return;
			}
			try {
				setState(deserializeState(event.newValue));
			} catch {
				// ignore
			}
		};
		window.addEventListener("storage", onStorage);
		return () => window.removeEventListener("storage", onStorage);
	}, []);

	const persist = useCallback((next: UserCampingState) => {
		setState(next);
		try {
			window.localStorage.setItem(STORAGE_KEY, serializeState(next));
		} catch {
			// ignore quota / privacy mode
		}
	}, []);

	const exportJson = useCallback(() => serializeState(state), [state]);

	const importJson = useCallback(
		(raw: string, mode: MergeMode) => {
			const incoming = deserializeState(raw);
			if (mode === "replace") {
				persist(
					new UserCampingState({
						version: CURRENT_USER_CAMPING_STATE_VERSION,
						favorites: incoming.favorites,
						reviews: incoming.reviews,
						draftCampingSpots: incoming.draftCampingSpots,
					}),
				);
				return;
			}
			persist(
				new UserCampingState({
					version: CURRENT_USER_CAMPING_STATE_VERSION,
					favorites: { ...state.favorites, ...incoming.favorites },
					reviews: { ...state.reviews, ...incoming.reviews },
					draftCampingSpots: {
						...state.draftCampingSpots,
						...incoming.draftCampingSpots,
					},
				}),
			);
		},
		[persist, state],
	);

	const clear = useCallback(() => {
		persist(emptyUserCampingState());
	}, [persist]);

	const toggleFavorite = useCallback(
		(type: EntityKind, id: string) => {
			const ref = new EntityRef({ type, id });
			const key = favoriteKey(ref);
			const next = new UserCampingState({
				version: state.version,
				favorites: { ...state.favorites, [key]: !state.favorites[key] },
				reviews: state.reviews,
				draftCampingSpots: state.draftCampingSpots,
			});
			persist(next);
		},
		[persist, state],
	);

	const isFavorite = useCallback(
		(type: EntityKind, id: string) => {
			const key = encodeEntityRefKey(new EntityRef({ type, id }));
			return Boolean(state.favorites[key]);
		},
		[state.favorites],
	);

	const setReview = useCallback(
		(review: ReviewEntry) => {
			const key = favoriteKey(review.ref);
			persist(
				new UserCampingState({
					version: state.version,
					favorites: state.favorites,
					reviews: { ...state.reviews, [key]: review },
					draftCampingSpots: state.draftCampingSpots,
				}),
			);
		},
		[persist, state],
	);

	const upsertDraftCampingSpot = useCallback(
		(draft: DraftCampingSpot) => {
			persist(
				new UserCampingState({
					version: state.version,
					favorites: state.favorites,
					reviews: state.reviews,
					draftCampingSpots: {
						...state.draftCampingSpots,
						[draft.slug]: draft,
					},
				}),
			);
		},
		[persist, state],
	);

	const removeDraftCampingSpot = useCallback(
		(slug: string) => {
			const next = { ...state.draftCampingSpots };
			delete next[slug];
			persist(
				new UserCampingState({
					version: state.version,
					favorites: state.favorites,
					reviews: state.reviews,
					draftCampingSpots: next,
				}),
			);
		},
		[persist, state],
	);

	const value = useMemo(
		(): UserOverlayApi => ({
			hydrated,
			state,
			persist,
			exportJson,
			importJson,
			clear,
			toggleFavorite,
			isFavorite,
			setReview,
			upsertDraftCampingSpot,
			removeDraftCampingSpot,
		}),
		[
			hydrated,
			state,
			persist,
			exportJson,
			importJson,
			clear,
			toggleFavorite,
			isFavorite,
			setReview,
			upsertDraftCampingSpot,
			removeDraftCampingSpot,
		],
	);

	return (
		<UserOverlayContext.Provider value={value}>
			{children}
		</UserOverlayContext.Provider>
	);
}

export function useUserOverlay(): UserOverlayApi {
	const ctx = useContext(UserOverlayContext);
	if (ctx == null) {
		throw new Error("useUserOverlay must be used within UserOverlayProvider");
	}
	return ctx;
}

import type { CampingSpot, SurfSchool } from "@camping/domain-shared";

import { haversineKm } from "./geo.ts";

const MAX_NEIGHBORS = 8;
const MAX_KM = 120;

type WithCoords = { latitude: number; longitude: number };

/** Camping spots that list this surf school in `relatedSurfSchoolSlugs` (curated pairings). */
export function campingSpotsLinkedToSurfSchool(
	schoolSlug: string,
	spots: CampingSpot[],
): CampingSpot[] {
	return spots.filter((s) => s.relatedSurfSchoolSlugs?.includes(schoolSlug));
}

function distanceKmSchoolToCamping(
	school: SurfSchool,
	spot: CampingSpot,
): number {
	if (
		spot.latitude == null ||
		spot.longitude == null ||
		typeof spot.latitude !== "number" ||
		typeof spot.longitude !== "number"
	) {
		return Number.POSITIVE_INFINITY;
	}
	return haversineKm(
		school.latitude,
		school.longitude,
		spot.latitude,
		spot.longitude,
	);
}

/**
 * Campsites linked to this school or within {@link MAX_KM}, deduped,
 * sorted by great-circle distance (nearest first), capped at {@link MAX_NEIGHBORS}.
 */
export function surfSchoolRelatedCampingOptionsWithDistance(
	school: SurfSchool,
	spots: CampingSpot[],
): { spot: CampingSpot; distanceKm: number }[] {
	const linkedSlugs = new Set(
		campingSpotsLinkedToSurfSchool(school.slug, spots).map((c) => c.slug),
	);
	const rows: { spot: CampingSpot; distanceKm: number }[] = [];
	for (const spot of spots) {
		const linked = linkedSlugs.has(spot.slug);
		const distanceKm = distanceKmSchoolToCamping(school, spot);
		if (linked || distanceKm <= MAX_KM) {
			rows.push({ spot, distanceKm });
		}
	}
	return rows
		.sort((a, b) => {
			if (a.distanceKm !== b.distanceKm) {
				return a.distanceKm - b.distanceKm;
			}
			return a.spot.name.localeCompare(b.spot.name);
		})
		.slice(0, MAX_NEIGHBORS);
}

export function surfSchoolRelatedCampingOptions(
	school: SurfSchool,
	spots: CampingSpot[],
): CampingSpot[] {
	return surfSchoolRelatedCampingOptionsWithDistance(school, spots).map(
		({ spot }) => spot,
	);
}

/**
 * Surf schools within {@link MAX_KM} of the campsite, nearest first.
 */
export function nearbySchoolsForCampingWithDistance(
	spot: CampingSpot & WithCoords,
	schools: SurfSchool[],
): { school: SurfSchool; distanceKm: number }[] {
	return schools
		.map((s) => ({
			school: s,
			distanceKm: haversineKm(
				spot.latitude,
				spot.longitude,
				s.latitude,
				s.longitude,
			),
		}))
		.filter(({ distanceKm }) => distanceKm <= MAX_KM)
		.sort((a, b) => {
			if (a.distanceKm !== b.distanceKm) {
				return a.distanceKm - b.distanceKm;
			}
			return a.school.name.localeCompare(b.school.name);
		})
		.slice(0, MAX_NEIGHBORS);
}

export function nearbySchoolsForCamping(
	spot: CampingSpot & WithCoords,
	schools: SurfSchool[],
): SurfSchool[] {
	return nearbySchoolsForCampingWithDistance(spot, schools).map(
		({ school }) => school,
	);
}

