import path from "node:path";
import { fileURLToPath } from "node:url";

import contentCollections from "@content-collections/vite";
import tailwindcss from "@tailwindcss/vite";
import { devtools } from "@tanstack/devtools-vite";
import { tanstackStart } from "@tanstack/react-start/plugin/vite";
import viteReact from "@vitejs/plugin-react";
import { defineConfig } from "vite";

import { workspaceUiAliasPlugin } from "../../packages/ui/src/vite-workspace-ui-alias.ts";

const packageRoot = path.dirname(fileURLToPath(import.meta.url));
const monorepoRoot = path.resolve(packageRoot, "../..");
const uiPackageRoot = path.join(monorepoRoot, "packages", "ui");

const campingContentCollectionsConfig = fileURLToPath(
	new URL("../../packages/svc-camping-data/content-collections.ts", import.meta.url),
);

export default defineConfig({
	plugins: [
		workspaceUiAliasPlugin({ packageRoot, uiPackageRoot }),
		devtools(),
		tailwindcss(),
		contentCollections({ configPath: campingContentCollectionsConfig }),
		tanstackStart(),
		viteReact(),
	],
	resolve: {
		tsconfigPaths: true,
		dedupe: ["react", "react-dom", "@camping/ui"],
	},
	server: {
		fs: {
			allow: [monorepoRoot],
		},
	},
});

