import { parsePanelsUrlSearch, type SerializableProps } from "@camping/ui";
import { createFileRoute, getRouteApi } from "@tanstack/react-router";
import { useMemo } from "react";
import { ExploreSurfMap } from "../components/explore-map.tsx";
import { getCampingSpots, getRegions, getSurfSchools } from "../lib/catalog.ts";
import {
	CAMPING_SPOT_DETAIL_PANEL_TYPE,
	ExplorePanelsLayout,
	SURF_SCHOOL_DETAIL_PANEL_TYPE,
	useExplorePanels,
	validateExplorePanelsSearch,
} from "../panels";

const exploreRoute = getRouteApi("/explore");

export const Route = createFileRoute("/explore")({
	validateSearch: validateExplorePanelsSearch,
	component: ExploreRoute,
});

function slugFromPanelProps(
	propsMap: Record<string, SerializableProps>,
	panelType: string,
): string | null {
	const slug = propsMap[panelType]?.slug;
	return typeof slug === "string" ? slug : null;
}

/** Map URL panel stack / active panel to highlighted map entity (surf school vs camping). */
function useExploreMapHighlight(): {
	highlightedSchoolSlug: string | null;
	highlightedCampingSlug: string | null;
} {
	const search = exploreRoute.useSearch();
	return useMemo(() => {
		const parsed = parsePanelsUrlSearch(search);
		const focusType =
			parsed.activePanelType ??
			(parsed.openPanelTypes.length > 0
				? parsed.openPanelTypes[parsed.openPanelTypes.length - 1]!
				: null);
		if (!focusType) {
			return { highlightedSchoolSlug: null, highlightedCampingSlug: null };
		}
		if (focusType === SURF_SCHOOL_DETAIL_PANEL_TYPE) {
			return {
				highlightedSchoolSlug: slugFromPanelProps(parsed.panelPropsMap, focusType),
				highlightedCampingSlug: null,
			};
		}
		if (focusType === CAMPING_SPOT_DETAIL_PANEL_TYPE) {
			return {
				highlightedSchoolSlug: null,
				highlightedCampingSlug: slugFromPanelProps(parsed.panelPropsMap, focusType),
			};
		}
		return { highlightedSchoolSlug: null, highlightedCampingSlug: null };
	}, [search]);
}

function ExploreMain() {
	const { openPanel } = useExplorePanels();
	const { highlightedSchoolSlug, highlightedCampingSlug } = useExploreMapHighlight();

