import {
	CURRENT_USER_CAMPING_STATE_VERSION,
	type DraftCampingSpot,
	decodeUserCampingState,
	type EntityKind,
	EntityRef,
	emptyUserCampingState,
	favoriteKey,
	type ReviewEntry,
	type UserCampingState,
} from "@camping/domain-shared";
import { Option } from "effect";
import {
	createContext,
	type ReactNode,
	useCallback,
	useContext,
	useEffect,
	useMemo,
	useState,
} from "react";

/** localStorage key for {@link UserCampingState} (favorites, reviews, drafts). */
export const USER_CAMPING_STATE_STORAGE_KEY = "camping:user-camping-state-v1";

const STORAGE_KEY = USER_CAMPING_STATE_STORAGE_KEY;

const serializeState = (state: UserCampingState): string =>
	JSON.stringify({
		version: state.version,
		favorites: state.favorites,
		reviews: Object.fromEntries(
			Object.entries(state.reviews).map(([k, v]) => [
				k,
				{
					ref: { type: v.ref.type, id: v.ref.id },
					rating: v.rating,
					text: v.text,
					createdAt: v.createdAt,
					updatedAt: v.updatedAt,
				},
			]),
		),
		draftCampingSpots: Object.fromEntries(
			Object.entries(state.draftCampingSpots).map(([k, v]) => [
				k,
				{
					slug: v.slug,
					name: v.name,
					kind: v.kind,
					regionSlug: v.regionSlug,
					address: v.address,
					latitude: v.latitude,
					longitude: v.longitude,
					link: v.link,
					notes: v.notes,
					createdAt: v.createdAt,
					updatedAt: v.updatedAt,
				},
			]),
		),
	});

const deserializeState = (raw: string): UserCampingState => {
	const parsed = JSON.parse(raw) as unknown;
	const decoded = decodeUserCampingState(parsed);
	return Option.getOrElse(decoded, () => emptyUserCampingState());
};

export type MergeMode = "replace" | "merge";

/**
 * Browser localStorage–backed user overlay (favorites, reviews, draft campsites).
 * Implements the same shape as {@link import("@camping/domain-shared").UserOverlayStorePort}
 * synchronously; writes are applied after React state updates via a sync effect.
 */
export type UserOverlayApi = {
	/** True after first client read from `localStorage` (avoid mutating before load). */
	hydrated: boolean;
	state: UserCampingState;
	/** Replace overlay state and persist (effect writes `localStorage`). */
	persist: (next: UserCampingState) => void;
	exportJson: () => string;
	importJson: (raw: string, mode: MergeMode) => void;
	clear: () => void;
	toggleFavorite: (type: EntityKind, id: string) => void;
	isFavorite: (type: EntityKind, id: string) => boolean;
	setReview: (review: ReviewEntry) => void;
	upsertDraftCampingSpot: (draft: DraftCampingSpot) => void;
	removeDraftCampingSpot: (slug: string) => void;
};

const UserOverlayContext = createContext<UserOverlayApi | null>(null);

export function UserOverlayProvider({ children }: { children: ReactNode }) {
	const [hydrated, setHydrated] = useState(false);
	const [state, setState] = useState<UserCampingState>(() =>
		emptyUserCampingState(),
	);

	const loadFromStorage = useCallback(() => {
		if (typeof window === "undefined") return;
		try {
			const raw = window.localStorage.getItem(STORAGE_KEY);
			if (raw) setState(deserializeState(raw));
			else setState(emptyUserCampingState());
		} catch {
			// ignore
		}
	}, []);

	useEffect(() => {
		loadFromStorage();
		setHydrated(true);
	}, [loadFromStorage]);

	useEffect(() => {
		const onStorage = (event: StorageEvent) => {
			if (event.key !== STORAGE_KEY) return;
			if (event.newValue == null) {
				setState(emptyUserCampingState());
				return;
			}
			try {
				setState(deserializeState(event.newValue));
			} catch {
				// ignore
			}
		};
		window.addEventListener("storage", onStorage);
		return () => window.removeEventListener("storage", onStorage);
	}, []);

	/** Persist in-memory state to `localStorage` after hydration (single writer). */
	useEffect(() => {
		if (!hydrated || typeof window === "undefined") return;
		try {
			window.localStorage.setItem(STORAGE_KEY, serializeState(state));
		} catch {
			// ignore quota / privacy mode
		}
	}, [state, hydrated]);

	const persist = useCallback((next: UserCampingState) => {
		setState(next);
	}, []);

	const exportJson = useCallback(() => serializeState(state), [state]);

	const importJson = useCallback(
		(raw: string, mode: MergeMode) => {
			const incoming = deserializeState(raw);
			if (mode === "replace") {
				persist(
					new UserCampingState({
						version: CURRENT_USER_CAMPING_STATE_VERSION,
						favorites: incoming.favorites,
						reviews: incoming.reviews,
						draftCampingSpots: incoming.draftCampingSpots,
					}),
				);
				return;
			}
			setState((prev) =>
				new UserCampingState({
					version: CURRENT_USER_CAMPING_STATE_VERSION,
					favorites: { ...prev.favorites, ...incoming.favorites },
					reviews: { ...prev.reviews, ...incoming.reviews },
					draftCampingSpots: {
						...prev.draftCampingSpots,
						...incoming.draftCampingSpots,
					},
				}),
			);
		},
		[persist],
	);

	const clear = useCallback(() => {
		persist(emptyUserCampingState());
	}, [persist]);

	const toggleFavorite = useCallback((type: EntityKind, id: string) => {
		if (typeof window === "undefined") return;
		setState((prev) => {
			if (!hydrated) return prev;
			const ref = new EntityRef({ type, id });
			const key = favoriteKey(ref);
			return new UserCampingState({
				version: prev.version,
				favorites: { ...prev.favorites, [key]: !prev.favorites[key] },
				reviews: prev.reviews,
				draftCampingSpots: prev.draftCampingSpots,
			});
		});
	}, [hydrated]);

	const isFavorite = useCallback(
		(type: EntityKind, id: string) => {
			const key = favoriteKey(new EntityRef({ type, id }));
			return Boolean(state.favorites[key]);
		},
		[state.favorites],
	);

	const setReview = useCallback(
		(review: ReviewEntry) => {
			const key = favoriteKey(review.ref);
			setState((prev) =>
				new UserCampingState({
					version: prev.version,
					favorites: prev.favorites,
					reviews: { ...prev.reviews, [key]: review },
					draftCampingSpots: prev.draftCampingSpots,
				}),
			);
		},
		[],
	);

	const upsertDraftCampingSpot = useCallback((draft: DraftCampingSpot) => {
		setState((prev) =>
			new UserCampingState({
				version: prev.version,
				favorites: prev.favorites,
				reviews: prev.reviews,
				draftCampingSpots: {
					...prev.draftCampingSpots,
					[draft.slug]: draft,
				},
			}),
		);
	}, []);

	const removeDraftCampingSpot = useCallback((slug: string) => {
		setState((prev) => {
			const next = { ...prev.draftCampingSpots };
			delete next[slug];
			return new UserCampingState({
				version: prev.version,
				favorites: prev.favorites,
				reviews: prev.reviews,
				draftCampingSpots: next,
			});
		});
	}, []);

	const value = useMemo(
		(): UserOverlayApi => ({
			hydrated,
			state,
			persist,
			exportJson,
			importJson,
			clear,
			toggleFavorite,
			isFavorite,
			setReview,
			upsertDraftCampingSpot,
			removeDraftCampingSpot,
		}),
		[
			hydrated,
			state,
			persist,
			exportJson,
			importJson,
			clear,
			toggleFavorite,
			isFavorite,
			setReview,
			upsertDraftCampingSpot,
			removeDraftCampingSpot,
		],
	);

	return (
		<UserOverlayContext.Provider value={value}>
			{children}
		</UserOverlayContext.Provider>
	);
}

export function useUserOverlay(): UserOverlayApi {
	const ctx = useContext(UserOverlayContext);
	if (ctx == null) {
		throw new Error("useUserOverlay must be used within UserOverlayProvider");
	}
	return ctx;
}

/**
 * Mutation-style hook for favorite toggles (localStorage-backed via {@link UserOverlayProvider}).
 * Use for save / heart controls so handlers stay stable and respect hydration.
 */
export function useFavoriteToggle(type: EntityKind, id: string) {
	const { hydrated, isFavorite, toggleFavorite } = useUserOverlay();
	const saved = isFavorite(type, id);
	const mutateToggle = useCallback(() => {
		toggleFavorite(type, id);
	}, [toggleFavorite, type, id]);
	return { saved, mutateToggle, hydrated };
}

